    import os, re
    codex_file = os.path.join(os.path.dirname(__file__), "..", "..", "..", "commands", "codex.md")
    with open(codex_file) as f:
        content = f.read()

    # Extract Step 2 block
    step2_start = content.find("### 2. Generate unique output path")
    step3_start = content.find("### 3. Review mode")
    assert step2_start != -1, "Could not find Step 2 heading in commands/codex.md"
    assert step3_start != -1, "Could not find Step 3 heading in commands/codex.md"
    step2_block = content[step2_start:step3_start]

